def token_f1(a, b):
    ta = normalize(a).split()
    tb = normalize(b).split()
    if not ta or not tb:
        return 0.0
    from collections import Counter
    ca = Counter(ta)
    cb = Counter(tb)
    inter = sum((ca & cb).values())
    prec = inter / len(ta)
    rec = inter / len(tb)
    if prec + rec == 0:
        return 0.0
    return 2 * prec * rec / (prec + rec)

def lcs_ratio(a, b):
    sa = normalize(a)
    sb = normalize(b)
    # approximate using difflib
    sm = difflib.SequenceMatcher(None, sa, sb)
    return sm.ratio()

def combined_score(a, b):
    return 0.5 * token_f1(a, b) + 0.5 * lcs_ratio(a, b)

